Here's a function that compares the keys between two nested objects and returns the missing keys along with their corresponding values from the second object:

```javascript
const compareKeys = (obj1, obj2) => {
  const differences = {};

  const checkKeys = (source, target) => {
    Object.keys(target).forEach((key) => {
      if (!source.hasOwnProperty(key)) {
        differences[key] = target[key];
      } else if (typeof source[key] === "object" && typeof target[key] === "object") {
        checkKeys(source[key], target[key]);
      }
    });
  };

  checkKeys(obj1, obj2);

  return differences;
};
```

You can use this function like this:

```javascript
const obj1 = {
  a: {
    b: "value 1",
    c: "value 2",
  },
  d: "value 3",
};

const obj2 = {
  a: {
    b: "value 1",
    c: "value 2",
    d: "value 4",
  },
  e: "value 5",
};

const differences = compareKeys(obj1, obj2);
console.log(differences);
```

The output will be:

```
{
  a: {
    d: "value 4"
  },
  e: "value 5"
}
```

